<div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h1 class="h4">New Work Order Template</h1><form method="post" action="/portal/work-order-templates" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Name</label><input name="name" class="form-control" required></div><div class="col-12"><label class="form-label">Default Service</label><select name="service_id" class="form-select"><option value="">None</option><?php foreach($services as $s):?><option value="<?=$s['id']?>"><?=e($s['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Summary</label><input name="service_summary" class="form-control"></div><div class="col-12"><label class="form-label">Default Duration (minutes)</label><input type="number" name="default_duration_minutes" class="form-control"></div><div class="col-12"><label class="form-label">Instructions</label><textarea name="instructions" class="form-control" rows="4"></textarea></div><div class="col-12 form-check ms-2"><input type="checkbox" name="active" checked class="form-check-input" id="woa"><label for="woa" class="form-check-label">Active</label></div><div class="col-12"><button class="btn btn-primary w-100">Create Template</button></div></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Name</th><th>Service</th><th>Duration</th><th>Tasks</th><th></th></tr></thead><tbody><?php foreach($templates as $t):?><tr><td><?=e($t['name'])?></td><td><?=e($t['service_name']??'Any')?></td><td><?=e((string)($t['default_duration_minutes']??''))?></td><td><?=$t['task_count']?></td><td><a class="btn btn-sm btn-outline-primary" href="/portal/work-order-templates/<?=$t['id']?>">Configure</a></td></tr><?php endforeach?></tbody></table></div></div></div></div>
